import request from '@/utils/request'
import { STORAGE_KEYS, clearAuthStorage } from '@/utils/storage'

// 认证相关的核心功能
export const auth = {
  // 密码登录
  loginWithPassword: (data) => {
    return request.post('/api/v1/users/auth/login/password/', data)
  },

  // 退出登录
  logout: async () => {
    const refreshToken = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN)
    if (!refreshToken) return
    try {
      await request.post('/api/v1/users/auth/logout/', { refresh: refreshToken })
    } finally {
      // 无论请求是否成功，都清除本地存储
      clearAuthStorage()
    }
  },

  // 刷新 token
  refreshToken: (data) => {
    return request.post('/api/v1/users/auth/token/refresh/', data)
  },

  // 更新用户名（昵称）
  updateUsername: (data) => {
    return request.post('/api/v1/users/account/username/', data)
  },

  // 更新密码
  updatePassword: (data) => {
    return request.post('/api/v1/users/account/password/', data)
  },

  // 发送验证码
  sendVerifyCode: (data) => {
    return request.post('/api/v1/users/auth/sms/send/', data)
  },

  // 更换手机号
  changePhone: (data) => {
    return request.post('/api/v1/users/account/phone/', data)
  },

  // 删除账户
  deleteAccount: (data) => {
    return request.post('/api/v1/users/account/delete/', data)
  },

  // 获取用户信息
  getUserInfo: () => {
    return request.get('/api/v1/users/info/')
  }
}

export default auth
